def combinations(n, k):
    if k < 0 or k > n: return 0
    res = 1
    for i in range(k):
        res = res * (n - i) // (i + 1)
    return res

if __name__ == "__main__":
    print(f"52 choose 5: {combinations(52, 5)}")

